import os,zlib
base='.git/objects'
objs={}
for d in os.listdir(base):
  if len(d)!=2: continue
  p=os.path.join(base,d)
  if not os.path.isdir(p): continue
  for f in os.listdir(p):
    raw=open(os.path.join(p,f),'rb').read();dec=zlib.decompress(raw)
    h,cont=dec.split(b'\x00',1);t=h.decode().split()[0];objs[d+f]=(t,cont)

def tree_entries(b):
 i=0;res=[]
 while i<len(b):
  j=b.find(b' ',i);mode=b[i:j].decode();i=j+1
  j=b.find(b'\x00',i);name=b[i:j].decode();i=j+1
  sha=b[i:i+20].hex();i+=20
  res.append((mode,name,sha))
 return res

def walk(tree,p=''):
 for m,n,s in tree_entries(objs[tree][1]):
  full=f'{p}/{n}' if p else n
  t=objs[s][0]
  print(full,t,s)
  if t=='tree': walk(s,full)

